1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
3	
4	type Item = { type: string; cursed?: boolean; enchantment?: number };
5	type Customer = { yearsWithMHPCO: number };
6	type QuoteStep = { op: "quote"; items: Item[] };
7	type Damage = { itemType: string; amount: number };
8	type Incident = { cause: string; damages: Damage[] };
9	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
10	type Step = QuoteStep | ClaimStep;
11	type Scenario = { customer: Customer; steps: Step[] };
12	
13	type ItemKind = {
14	  basePremium: number;
15	  insuranceValue: number;
16	  isComponent: boolean;
17	};
18	
19	const ITEM_CATALOG: Record<string, ItemKind> = {
20	  sword: { basePremium: 100, insuranceValue: 1000, isComponent: false },
21	  amulet: { basePremium: 60, insuranceValue: 600, isComponent: false },
22	  staff: { basePremium: 80, insuranceValue: 800, isComponent: false },
23	  potion: { basePremium: 40, insuranceValue: 400, isComponent: false },
24	  rune: { basePremium: 25, insuranceValue: 250, isComponent: true },
25	  moonstone: { basePremium: 25, insuranceValue: 250, isComponent: true },
26	};
27	
28	const BLOCK_PRICE = 60;
29	const BLOCK_SIZE = 3;
30	
31	const countByType = (items: Item[]): Record<string, number> =>
32	  items.reduce<Record<string, number>>((counts, item) => {
33	    counts[item.type] = (counts[item.type] ?? 0) + 1;
34	    return counts;
35	  }, {});
36	
37	const premiumForTypeGroup = (type: string, count: number): number => {
38	  const kind = ITEM_CATALOG[type];
39	  const formsBlock = kind.isComponent && count === BLOCK_SIZE;
40	  return formsBlock ? BLOCK_PRICE : kind.basePremium * count;
41	};
42	
43	const policyBaseFor = (items: Item[]): number =>
44	  Object.entries(countByType(items)).reduce(
45	    (total, [type, count]) => total + premiumForTypeGroup(type, count),
46	    0,
47	  );
48	
49	const CURSE_SURCHARGE_RATE = 0.5;
50	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
51	const HIGH_ENCHANTMENT_THRESHOLD = 5;
52	
53	const isCursed = (item: Item): boolean => item.cursed === true;
54	const isHighlyEnchanted = (item: Item): boolean =>
55	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
56	
57	const itemSurchargeFor = (item: Item): number => {
58	  const basePremium = ITEM_CATALOG[item.type].basePremium;
59	  const curseSurcharge = isCursed(item) ? basePremium * CURSE_SURCHARGE_RATE : 0;
60	  const highEnchantmentSurcharge = isHighlyEnchanted(item)
61	    ? basePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE
62	    : 0;
63	  return curseSurcharge + highEnchantmentSurcharge;
64	};
65	
66	const perItemSurchargesFor = (items: Item[]): number =>
67	  items.reduce((total, item) => total + itemSurchargeFor(item), 0);
68	
69	const LOYALTY_THRESHOLD_YEARS = 2;
70	const LOYALTY_DISCOUNT_PERCENT = 20;
71	const FOLLOW_UP_DISCOUNT_PERCENT = 15;
72	
73	const percentOf = (amount: number, percent: number): number =>
74	  (amount * percent) / 100;
75	
76	const isLoyalCustomer = (customer: Customer): boolean =>
77	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
78	
79	const percentOfIf = (amount: number, percent: number, condition: boolean): number =>
80	  condition ? percentOf(amount, percent) : 0;
81	
82	const applyPolicyModifiers = (
83	  policyBase: number,
84	  customer: Customer,
85	  isFollowUp: boolean,
86	): number => {
87	  const firstInsuranceSurcharge = percentOf(policyBase, FIRST_INSURANCE_SURCHARGE_PERCENT);
88	  const loyaltyDiscount = percentOfIf(policyBase, LOYALTY_DISCOUNT_PERCENT, isLoyalCustomer(customer));
89	  const followUpDiscount = percentOfIf(policyBase, FOLLOW_UP_DISCOUNT_PERCENT, isFollowUp);
90	  return policyBase + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount;
91	};
92	
93	const premiumFor = (items: Item[], customer: Customer, isFollowUp: boolean): number =>
94	  Math.ceil(
95	    applyPolicyModifiers(policyBaseFor(items), customer, isFollowUp) +
96	      perItemSurchargesFor(items) +
97	      PROCESSING_FEE,
98	  );
99	
100	const runQuoteStep = (
101	  step: QuoteStep,
102	  customer: Customer,
103	  isFollowUp: boolean,
104	): { premium: number } => ({
105	  premium: premiumFor(step.items, customer, isFollowUp),
106	});
107	
108	const DEDUCTIBLE = 100;
109	
110	const insuranceSumFor = (items: Item[]): number =>
111	  items.reduce((total, item) => total + ITEM_CATALOG[item.type].insuranceValue, 0);
112	
113	type PolicyState = { remainingCap: number };
114	
115	const runClaimStep = (
116	  step: ClaimStep,
117	  policies: PolicyState[],
118	): { payout: number; remainingCap: number } => {
119	  const policy = policies[step.policy];
120	  const payout = step.incident.damages.reduce((total, damage) => {
121	    const raw = Math.max(0, damage.amount - DEDUCTIBLE);
122	    return total + Math.min(raw, policy.remainingCap - total);
123	  }, 0);
124	  policy.remainingCap -= payout;
125	  return { payout, remainingCap: policy.remainingCap };
126	};
127	
128	export const runScenario = (input: unknown): unknown => {
129	  const scenario = input as Scenario;
130	  const policies: PolicyState[] = [];
131	  let quoteCount = 0;
132	  const results = scenario.steps.map((step) => {
133	    if (step.op === "claim") {
134	      return runClaimStep(step, policies);
135	    }
136	    const isFollowUp = quoteCount > 0;
137	    quoteCount++;
138	    policies.push({ remainingCap: insuranceSumFor(step.items) * 2 });
139	    return runQuoteStep(step, scenario.customer, isFollowUp);
140	  });
141	  return { results };
142	};
