const DEDUCTIBLE = 100;

const insuranceSumFor = (items: Item[]): number =>
  items.reduce((total, item) => total + ITEM_CATALOG[item.type].insuranceValue, 0);

type PolicyState = { remainingCap: number };

const payoutForDamage = (damage: Damage): number =>
  Math.max(0, damage.amount - DEDUCTIBLE);

const runClaimStep = (
  step: ClaimStep,
  policies: PolicyState[],
): { payout: number; remainingCap: number } => {
  const policy = policies[step.policy];
  const payout = step.incident.damages.reduce((total, damage) => {
    const remainingRoom = policy.remainingCap - total;
    return total + Math.min(payoutForDamage(damage), remainingRoom);
  }, 0);
  policy.remainingCap -= payout;
  return { payout, remainingCap: policy.remainingCap };
};
